import {
  setup,
  assign,
  fromObservable,
  type Subscribable,
} from 'xstate';

type TickEvent = { type: 'TICK'; n: number };
type TickInput = { intervalMs: number };

const tickerActor = fromObservable<TickEvent, TickInput>(({ input }) => {
  const stream: Subscribable<TickEvent> = {
    subscribe(observer) {
      let n = 0;
      const id = setInterval(() => {
        const ev: TickEvent = { type: 'TICK', n: ++n };
        if (typeof observer === 'function') observer(ev);
        else observer.next?.(ev);
      }, input.intervalMs);
      return { unsubscribe: () => clearInterval(id) };
    },
  };
  return stream;
});

export const tickerMachine = setup({
  types: {
    context: {} as { lastTick: number },
    events: {} as TickEvent,
  },
  actors: { tickerActor },
}).createMachine({
  id: 'ticker',
  context: { lastTick: 0 },
  initial: 'running',
  states: {
    running: {
      invoke: {
        src: 'tickerActor',
        input: { intervalMs: 1000 },
      },
      on: {
        TICK: {
          actions: assign({ lastTick: ({ event }) => event.n }),
        },
      },
    },
  },
});
