  sendTo,
  sendParent,
  assign,
  type ActorRefFrom,
} from 'xstate';

// v4 had a single `send(event, { to })` action creator. v5 splits it:
// - `sendTo(target, event)` replaces `send(..., { to })`.
// - `sendParent(event)` is unchanged in spirit but imports from 'xstate'.

const child = setup({
  types: { context: {} as {}, events: {} as { type: 'X' } },
}).createMachine({
  id: 'child',
  on: { X: { actions: sendParent({ type: 'Y' } as const) } },
});

type ChildRef = ActorRefFrom<typeof child>;

export const parent = setup({
  types: {
    context: {} as { child: ChildRef | null; ys: number },
    events: {} as { type: 'INIT' } | { type: 'GO' } | { type: 'Y' },
  },
  actors: { child },
}).createMachine({
  id: 'parent',
  context: { child: null, ys: 0 },
  on: {
    INIT: {
      actions: assign({
        child: ({ spawn }) => spawn('child', { id: 'childId' }),
      }),
    },
    GO: { actions: sendTo('childId', { type: 'X' }) },
    Y: { actions: assign({ ys: ({ context }) => context.ys + 1 }) },
  },
});
```

