`sendTo(target, event)` is the v5 replacement for v4's `send(event, { to })`. `target` is either a string id (the id you used when spawning or invoking the child) or a function that reads the actor ref from context. `sendParent(event)` dispatches an event from a child up to its parent actor — handy for replies. Both should carry typed events so the receiver's `on:` handlers get narrowed properly.

```ts
import {
  setup,
  assign,
  sendTo,
  sendParent,
  type ActorRefFrom,
} from 'xstate';

const pongActor = setup({
  types: {
    context: {} as {},
    events: {} as { type: 'PING'; n: number },
  },
}).createMachine({
  id: 'pong',
  on: {
    PING: {
      actions: sendParent(({ event }) => ({
        type: 'PONG' as const,
        n: event.n,
      })),
    },
  },
});

type PongRef = ActorRefFrom<typeof pongActor>;

export const pingMachine = setup({
  types: {
    context: {} as { pong: PongRef | null; count: number },
    events: {} as
      | { type: 'INIT' }
      | { type: 'PING' }
      | { type: 'PONG'; n: number },
  },
  actors: { pongActor },
}).createMachine({
  id: 'ping',
  context: { pong: null, count: 0 },
  initial: 'idle',
  states: {
    idle: {
      on: {
        INIT: {
          target: 'active',
          actions: assign({
            pong: ({ spawn }) => spawn('pongActor', { id: 'pong' }),
          }),
        },
      },
    },
    active: {
      on: {
        PING: {
          actions: sendTo('pong', ({ context }) => ({
            type: 'PING' as const,
            n: context.count + 1,
          })),
        },
        PONG: {
          actions: assign({ count: ({ event }) => event.n }),
        },
      },
    },
  },
});
