import {
  setup,
  assign,
  sendTo,
  sendParent,
  type ActorRefFrom,
} from 'xstate';

const subscriber = setup({
  types: {
    context: {} as { received: number },
    events: {} as { type: 'NOTIFY'; topic: string },
    input: {} as { name: string },
  },
}).createMachine({
  id: 'subscriber',
  context: { received: 0 },
  on: {
    NOTIFY: {
      actions: [
        assign({ received: ({ context }) => context.received + 1 }),
        sendParent(({ event }) => ({
          type: 'RECEIPT' as const,
          topic: event.topic,
        })),
      ],
    },
  },
});

type SubRef = ActorRefFrom<typeof subscriber>;

export const hub = setup({
  types: {
    context: {} as { subs: Record<string, SubRef>; receipts: number },
    events: {} as
      | { type: 'SUBSCRIBE'; id: string }
      | { type: 'PUBLISH'; topic: string }
      | { type: 'RECEIPT'; topic: string },
  },
  actors: { subscriber },
}).createMachine({
  id: 'hub',
  context: { subs: {}, receipts: 0 },
  on: {
    SUBSCRIBE: {
      actions: assign({
        subs: ({ context, event, spawn }) => ({
          ...context.subs,
          [event.id]: spawn('subscriber', {
            id: event.id,
            input: { name: event.id },
          }),
        }),
      }),
    },
    PUBLISH: {
      actions: ({ context, event, self }) => {
        for (const id of Object.keys(context.subs)) {
          self.send({ type: '__fanout__' } as never);
          // Fan out via sendTo by id per subscriber.
          context.subs[id]!.send({ type: 'NOTIFY', topic: event.topic });
        }
      },
    },
    RECEIPT: {
      actions: assign({ receipts: ({ context }) => context.receipts + 1 }),
    },
  },
});

// sendTo form shown here for completeness on a single-subscriber shortcut:
export const hubDirect = setup({
  types: {
    context: {} as { one: SubRef | null },
    events: {} as
      | { type: 'START' }
      | { type: 'PUBLISH'; topic: string },
  },
  actors: { subscriber },
}).createMachine({
  id: 'hubDirect',
  context: { one: null },
  on: {
    START: {
      actions: assign({
        one: ({ spawn }) =>
          spawn('subscriber', { id: 'one', input: { name: 'one' } }),
      }),
    },
    PUBLISH: {
      actions: sendTo('one', ({ event }) => ({
        type: 'NOTIFY' as const,
