import {
  setup,
  assign,
  sendTo,
  sendParent,
  type ActorRefFrom,
} from 'xstate';

const child = setup({
  types: {
    context: {} as {},
    events: {} as { type: 'REQ'; id: number },
  },
}).createMachine({
  id: 'child',
  on: {
    REQ: {
      actions: sendParent(({ event }) => ({
        type: 'RES' as const,
        id: event.id,
      })),
    },
  },
});

type ChildRef = ActorRefFrom<typeof child>;

export const parent = setup({
  types: {
    context: {} as {
      child: ChildRef | null;
      sent: number;
      got: number;
      target: number;
    },
    events: {} as
      | { type: 'START'; target: number }
      | { type: 'STEP' }
      | { type: 'RES'; id: number },
  },
  actors: { child },
  guards: {
    reachedTarget: ({ context }) => context.got + 1 >= context.target,
  },
}).createMachine({
  id: 'parent',
  context: { child: null, sent: 0, got: 0, target: 0 },
  initial: 'idle',
  states: {
    idle: {
      on: {
        START: {
          target: 'running',
          actions: assign({
            child: ({ spawn }) => spawn('child', { id: 'c' }),
            target: ({ event }) => event.target,
            sent: 0,
            got: 0,
          }),
        },
      },
    },
    running: {
      on: {
        STEP: {
          actions: [
            sendTo('c', ({ context }) => ({
              type: 'REQ' as const,
              id: context.sent,
            })),
            assign({ sent: ({ context }) => context.sent + 1 }),
          ],
        },
        RES: [
          {
            guard: 'reachedTarget',
            target: 'done',
            actions: assign({ got: ({ context }) => context.got + 1 }),
          },
          {
            actions: assign({ got: ({ context }) => context.got + 1 }),
          },
        ],
      },
    },
    done: { type: 'final' },
  },
});
